const raw = $input.first().json;
const params = raw.parameters ?? {};
const ioc = params.ioc ?? params.value ?? params.indicator ?? null;
const iocType = params.ioc_type ?? params.type ?? 'ip-dst';
if (!ioc) throw new Error('Sandbox: parameters.ioc is required');
const proposedActionId = raw.proposed_action_id ?? 'unknown';
return [{ json: { ioc, ioc_type: iocType, proposed_action_id: proposedActionId, action: raw.action, requester: raw.requester } }];

const misp = $input.item.json;
const input = $('Normalise Input').first().json;
const attributes = misp.response?.Attribute ?? [];
const eventIds = [...new Set(attributes.map(a => a.event_id))];
const tags = attributes.flatMap(a => (a.Tag ?? []).map(t => t.name));
const uniqueTags = [...new Set(tags)];
const tlp = uniqueTags.find(t => t.toLowerCase().startsWith('tlp:')) ?? 'tlp:white';
const mispFound = attributes.length > 0;
return [{ json: { ...input, misp_found: mispFound, misp_attributes: attributes, misp_event_ids: eventIds, misp_tags: uniqueTags, tlp } }];

const cortex = $input.item.json;
const input = $('Parse MISP Results').first().json;
const jobId = cortex.id ?? null;
const status = cortex.status ?? 'unknown';
return [{ json: { ...input, cortex_job_id: jobId, cortex_status: status } }];

const opencti = $input.item.json;
const input = $('Parse Cortex Job').first().json;
const openctiId = opencti.data?.stixCyberObservableAdd?.id ?? null;
const success = !!openctiId;
const resultSummary = success
  ? `IOC ${input.ioc} (${input.ioc_type}) enriched. MISP hits: ${input.misp_attributes.length}. Cortex job: ${input.cortex_job_id}. OpenCTI ID: ${openctiId}.`
  : `IOC ${input.ioc} processed. MISP hits: ${input.misp_attributes.length}. OpenCTI push failed.`;
return [{ json: {
  status: success ? 'success' : 'partial',
  result_summary: resultSummary,
  raw_result_ref: openctiId,
  ioc: input.ioc,
  ioc_type: input.ioc_type,
  misp_found: input.misp_found,
  misp_event_ids: input.misp_event_ids,
  cortex_job_id: input.cortex_job_id,
  opencti_id: openctiId,
  proposed_action_id: input.proposed_action_id
} }];
